import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Login = ({ setIsLoggedIn }) => {
  const [email, setEmail] = useState('');
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault();
    // Simulamos éxito guardando un token en localStorage
    localStorage.setItem('token-falso', 'abc-123-xyz');
    setIsLoggedIn(true);
    navigate('/dashboard');
  };

  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '80vh' }}>
      <form onSubmit={handleLogin} style={formStyle}>
        <h2 style={{ textAlign: 'center', color: '#1e293b' }}>Bienvenido</h2>
        <p style={{ textAlign: 'center', color: '#64748b', fontSize: '0.9rem' }}>Ingresa para gestionar tus ofertas</p>
        
        <input 
          type="email" 
          placeholder="Tu correo electrónico" 
          required 
          style={inputStyle} 
          onChange={(e) => setEmail(e.target.value)}
        />
        <input 
          type="password" 
          placeholder="Tu contraseña" 
          required 
          style={inputStyle} 
        />
        
        <button type="submit" style={buttonStyle}>INGRESAR AL PANEL</button>
      </form>
    </div>
  );
};

const formStyle = { background: 'white', padding: '40px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', width: '100%', maxWidth: '400px' };
const inputStyle = { width: '100%', padding: '12px', margin: '10px 0', borderRadius: '10px', border: '1px solid #ddd', boxSizing: 'border-box' };
const buttonStyle = { width: '100%', padding: '12px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold', marginTop: '10px' };

export default Login;
